.darma-loader-darma-custom-367 {color: var(--loader-color, #0284c7);
  width: 60px;
  aspect-ratio: 1;
  display: flex;
}.darma-loader-darma-custom-367::before,.darma-loader-darma-custom-367::after {content:"";
  flex:1;
  animation: darma-loader-darma-custom-367-l14 1.5s -.25s infinite linear alternate both;
}.darma-loader-darma-custom-367::after {--s:-1,-1;
  animation-delay: .5s;
}@keyframes darma-loader-darma-custom-367-l14 {0%,30% {transform: scale(var(--s,1)) translate(0px) perspective(150px) rotateY(0deg);
  clip-path: polygon(50% 0,100% 0,100% 100%,50% 100%,0 75%,0 25%);
  background:var(--loader-color, #0284c7);
}37.5%{transform: scale(var(--s,1)) translate(-10px) perspective(150px) rotateX(0deg);
  clip-path: polygon(50% 0,100% 0,100% 100%,50% 100%,0 75%,0 25%);
  background:var(--loader-color, #0284c7);
}50% {transform: scale(var(--s,1)) translate(-10px) perspective(150px) rotateX(-90deg);
  clip-path: polygon(50% 0,100% 0,100% 100%,50% 100%,0 75%,0 25%);
  background:var(--loader-color, #0284c7);
  border-radius: 0}50.01%{transform: scale(var(--s,1)) translate(-10px) perspective(150px) rotateX(-90.1deg);
  clip-path: polygon(0 0,100% 0,100% 100%,50% 100%,0 100%,0 25%);
  background:var(--loader-secondary-color, #7dd3fc);
  border-radius: 100px 0 0 100px}62.5%{transform: scale(var(--s,1)) translate(-10px) perspective(150px) rotateX(-180deg);
  clip-path: polygon(0 0,100% 0,100% 100%,50% 100%,0 100%,0 25%);
  background:var(--loader-secondary-color, #7dd3fc);
  border-radius: 100px 0 0 100px}70%,100%{transform: scale(var(--s,1)) translate(0px) perspective(150px) rotateX(-180deg);
  clip-path: polygon(0 0,100% 0,100% 100%,50% 100%,0 100%,0 25%);
  background:var(--loader-secondary-color, #7dd3fc);
  border-radius: 100px 0 0 100px;
}}

